const pergunta = $json.pergunta_usuario || "";
const base = $json.base_encontrada || [];

return [
  {
    json: {
      groq_body: {
        model: "llama-3.3-70b-versatile",

        messages: [
          {
            role: "system",
            content: `Você é um assistente de suporte técnico da Nola, uma empresa de tecnologia para gestão de restaurantes.

Seu papel é ajudar clientes com dúvidas sobre o sistema, sempre com clareza, cordialidade e objetividade.

Regras:
1. Responda apenas com base nas informações fornecidas na base de conhecimento.
2. Não invente funcionalidades, telas ou procedimentos.
3. Se a base não tiver informação suficiente, diga que não encontrou a resposta na base e recomende abrir ou encaminhar um chamado para o time de Customer Success.
4. Quando possível, responda em passos numerados.
5. Se identificar que pode ser bug, oriente coletar evidências como print, horário, loja afetada e descrição do comportamento.
6. Mantenha tom profissional, simples e humano.`
          },

          {
            role: "user",
            content: `Pergunta do cliente:
${pergunta}

Base de conhecimento encontrada:
${JSON.stringify(base, null, 2)}`
          }
        ],

        temperature: 0.2,
        max_tokens: 600
      }
    }
  }
];

const userQuestion = $('When chat message received').first().json.chatInput || "";

const normalizedQuestion = userQuestion
  .toLowerCase()
  .replace(/[.,;:!?()[\]{}"']/g, " ");

const questionWords = normalizedQuestion
  .split(/\s+/)
  .filter(word => word.length > 2);

function normalizeText(text) {
  return String(text || "")
    .toLowerCase()
    .replace(/[.,;:!?()[\]{}"']/g, " ");
}

function calculateScore(row) {
  const baseText = normalizeText(`
    ${row.categoria || ""}
    ${row.pergunta || ""}
    ${row.resposta || ""}
    ${row.palavras_chave || ""}
  `);

  let score = 0;

  for (const word of questionWords) {
    if (baseText.includes(word)) {
      score++;
    }
  }

  if (baseText.includes(normalizedQuestion.trim())) {
    score += 5;
  }

  return score;
}

const rows = items.map(item => item.json);

const rankedRows = rows
  .map(row => ({
    ...row,
    score: calculateScore(row),
  }))
  .filter(row => row.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 5);

return [
  {
    json: {
      pergunta_usuario: userQuestion,
      base_encontrada: rankedRows,
      encontrou_base: rankedRows.length > 0,
    },
  },
];
